const body = $input.first().json.body;
return [{
  json: {
    contrato_id: body.contrato_id || '',
    cliente_nome: body.cliente_nome || '',
    cliente_email: body.cliente_email || '',
    link_drive: body.link_drive || '',
    aprovado_por: body.aprovado_por || '',
    aprovado_por_email: body.aprovado_por_email || '',
    data_aprovacao: body.data_aprovacao || new Date().toISOString()
  }
}];

// Pega o link do item atual
const link = $('Extrair Dados do Body').first().json.link_drive;

// Regex para capturar o ID entre /d/ e /edit
const match = link.match(/\/d\/([^/]+)/);

// Se encontrar, retorna apenas o ID
return [
  {
    json: {
      id: match ? match[1] : null
    }
  }
];

